<?php
/*
Plugin Name: Custom User Profile Display (Direct DB)
Description: Displays user profile information based on a URL parameter using direct $wpdb queries.
Version: 1.0.0
*/

if (!defined('ABSPATH')) {
    exit;
}

function cupd_render_user_profile_by_url_param() {
    if (!isset($_GET['user_id'])) {
        return '';
    }

    $user_id = absint($_GET['user_id']);
    if ($user_id <= 0) {
        return '';
    }

    global $wpdb;

    $users_table = $wpdb->prefix . 'custom_users';

    $sql = $wpdb->prepare(
        "SELECT id, username, display_name, email, first_name, last_name, membership_level, status, created_at
         FROM {$users_table}
         WHERE id = %d
         LIMIT 1",
        $user_id
    );

    $user = $wpdb->get_row($sql, ARRAY_A);

    if (empty($user)) {
        return '';
    }

    $out  = '<div class="cupd-user-profile">';
    $out .= '<h2 class="cupd-display-name">' . esc_html($user['display_name'] !== '' ? $user['display_name'] : $user['username']) . '</h2>';

    $out .= '<ul class="cupd-user-fields">';
    $out .= '<li><strong>User ID:</strong> ' . esc_html($user['id']) . '</li>';
    $out .= '<li><strong>Username:</strong> ' . esc_html($user['username']) . '</li>';

    if (!empty($user['first_name']) || !empty($user['last_name'])) {
        $out .= '<li><strong>Name:</strong> ' . esc_html(trim($user['first_name'] . ' ' . $user['last_name'])) . '</li>';
    }

    if (!empty($user['email'])) {
        $out .= '<li><strong>Email:</strong> ' . esc_html($user['email']) . '</li>';
    }

    if (!empty($user['membership_level'])) {
        $out .= '<li><strong>Membership:</strong> ' . esc_html($user['membership_level']) . '</li>';
    }

    if (!empty($user['status'])) {
        $out .= '<li><strong>Status:</strong> ' . esc_html($user['status']) . '</li>';
    }

    if (!empty($user['created_at'])) {
        $out .= '<li><strong>Joined:</strong> ' . esc_html($user['created_at']) . '</li>';
    }

    $out .= '</ul>';
    $out .= '</div>';

    return $out;
}

add_shortcode('custom_user_profile', 'cupd_render_user_profile_by_url_param');